css:
/*【青春记事簿▪】作者：易碎蝶*/

/*🍃←这个是可以调整的部分，以及用了【这个符号】*/

/* ====== 全局字体设置 ====== */
@import url("https://fontsapi.zeoseven.com/293/main/result.css");

body {
    font-family: "LXGW WenKai Mono";
    font-weight: normal;
}
/*———————— 移动端顶栏背景 ————————*/
#top-bar {
    position: fixed !important;  /* 改为固定定位适配移动端 */
    overflow: visible !important;
    background: none !important;
    border: 0 !important;
    box-shadow: none !important;
    pointer-events: none;
    width: 100vw;  /* 全屏宽度 */
    height: 77px;  /* 适合移动端的顶部高度 */
    top: 0;
    left: 0;
}

#top-bar::before {
    content: "";
    position: fixed;
    background:  url("https://i.postimg.cc/bwthZ3yW/Image-2704773035465524.png") no-repeat center / cover;  /* 使用cover适配屏幕 */

    /* 移动端适配定位 */
    top: 0px;
    left: 0px;
    right: 0px;
    bottom: 40px;

    /* 层级控制 */
    z-index: 5;
    pointer-events: auto;

    /* 移除动画相关属性 */
    transform: none !important;
    animation: none !important;
}



/* —————面板背景图———— */
.drawer-content {
  background-image: url('https://i.postimg.cc/d0FzgYMB/Image-2643640805111726.png'); /* 示例图片URL */
  background-size: cover; /* 图片覆盖整个元素 */
  background-position: center; /* 图片居中显示 */
  background-repeat: no-repeat; /* 图片不重复 */
  background-attachment: fixed; /* 固定背景图片 */
}

/*——————滑块——————*/

input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 50px;
    height: 50px;
    background: transparent url('https://i.postimg.cc/2883RsYC/Image-2643185420880930.png') center/cover no-repeat;
    border: none;
    border-radius: 0;
    box-shadow: none;
    cursor: ew-resize;
    position: relative;
    z-index: 1;
}

/*——————最新消息箭头图标替换——————*/
/* ===== 隐藏原有字体图标 ===== */
.fa-chevron-right:before,
.fa-chevron-left:before,
.fa-arrow-right:before {
  content: "" !important;
  display: none !important; /* 双重保障隐藏图标 */
}

/* ===== 自定义箭头样式 ===== */
.fa-chevron-left,
.fa-chevron-right {
  display: inline-block;
  width: 90px;   /* 箭头图片宽度 */
  height: 50px;  /* 箭头图片高度 */
  background: center/contain no-repeat;
}

.fa-chevron-left {
  background-image: url('https://i.postimg.cc/0yzQr7r3/Image-2643180767375391.png'); /* 左箭头URL */
}


.fa-chevron-right {
  background-image: url('https://i.postimg.cc/BbN6PgTW/Image-2643183090065315.png'); /* 右箭头URL */
}

/* ===== 滑动计数器样式 ===== */
.swipes-counter {
  /* 文字样式 */
  color: var(--SmartThemeBodyColor);
  font-family: var(--mainFontFamily);
  font-size: 10px;
  font-weight: 540;

  /* 布局定位 */
  display: flex;
  justify-content: center;
  align-self: center;
  z-index: 3;

  /* 尺寸控制 */
  min-width: 0;
  height: var(--swipeCounterHeight); /* 高度变量 */
  padding: 0 60px;                 /* 水平内边距 */



  /* 间距控制 */
  margin: 
    var(--counter-vertical, 0)    /* 垂直间距，默认0 */
    var(--counter-horizonta, 0);  /* 水平间距，默认0 */
  margin-bottom: var(--swipeCounterMargin); /* 底部间距变量 */

  /* 备用定位方案 (需要时启用) */
  /* position: relative;
  left: var(--counter-left, 0);
  top: var(--counter-top, 0); */
}


/*——————装饰层——————*/
/* /* ==============================================
 * 1. 🍃装饰层模块
 * ==============================================*/
/* 🍃上层装饰层 - 位于气泡上方 */
.mes::before {
  content: "";
  position: absolute;
  top: -222px; /* 上层装饰层【上下】(负值表示向上) */
  left: -8.5px; /* 上层装饰层【左右】 */
  width: 384.3px; /* 调整上层装饰层的【宽度/大小】 */
  height: 530px; /* 调整上层装饰层的【高度/大小】 */
  background-image: url('https://i.postimg.cc/j2LTZMsH/Image-2630433822029708.png'); /* 替换为你的图片链接 - 上层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: -2; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}



/* 🍃下层装饰层 - 位于气泡下方，跟随气泡尾部移动 */
.mes::after {
  content: "";
  position: absolute;
  bottom: -165px; /* 下层装饰层【上下】(负值表示向下) */
  right: -60px; /* 下层装饰层【左右】 */
  width: 433px; /* 调整下层装饰层的【宽度/大小】 */
  height: 200.6px; /* 调整下层装饰层的【高度/大小】 */
  background-image: url('https://i.postimg.cc/T13kJNXT/Image-2635932933682652.png'); /* 替换为你的图片链接 - 下层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: -3; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}

/*——————🍃文本边距调整——————*/
/* 消息文本容器（可独立调整上下左右边距） */
.mes_text, 
.mes_reasoning {
    /* 基础样式 */
    font-weight: 500;
    line-height: calc(var(--mainFontSize) + .5rem);
    text-align: left; /* 文本左对齐 */
    overflow-wrap: anywhere;

    /* 🍃可独立调整的边距系统 */

    --top-padding:0rem; /* 气泡顶部留白 */
    --bottom-padding: 5rem; /* 气泡底部留白 */
    --left-padding: 1.3rem; /* 气泡左边距 */
    --right-padding: 0.8rem; /* 气泡右边距 */

    padding-top: var(--top-padding);
    padding-bottom: var(--bottom-padding);
    padding-left: var(--left-padding);
    padding-right: var(--right-padding);

    /* 最大宽度控制 */
    max-width: 700%;
    margin: 0; /* 清除默认外边距 */

    /* 气泡视觉相关样式（可根据UI需求扩展） */
    /* background-color: #f0f0f0; */
    /* border-radius: 19px; */
}






/*——————气泡设置——————*/

/* ==============================================
 * 1.🍃 气泡容器模块
 * ==============================================*/
.mes {
  color: #2E2E2E !important; /* 深棕色 */
  z-index: -3;
  max-width: 370px;/*【🍃宽度】*/
  width: 400%;/*【🍃宽度，一般调整第一个就行，没效果再调整这个】*/
  margin: 290px auto 60px;/*【AI和用户的气泡距离】*/
  border-radius: 0px;
  /* 移除渐变背景和阴影 */
  background: url('https://i.postimg.cc/W3pTJ2Cf/Image-2630441225943555.png') repeat-y; /* 添加重复方向 */
  background-size: 100% auto; /* 保持宽度适配 */
  background-attachment: local; /* 确保滚动时背景同步 */
  transition: transform 0.2s ease; /* 移除阴影过渡 */
  transform-origin: top center;
  position: relative;
  overflow: visible;
  box-shadow: none !important; /* 强制移除所有阴影 */
}

/* ==============================================
 * 头像装饰框修复版 (确保图片显示)
 * ============================================== */
/* 1. 确保头像容器有尺寸 */
.mesAvatarWrapper {
  position: absolute;
  top: -147px;
  left: 48.9%;
  transform: translateX(-50%);
  z-index: -1;

  /* 【新增】必须设置宽高 */
  width: 70px;  /* 头像宽度 */
  height: 70px; /* 头像高度 */
  overflow: visible; /* 允许装饰框超出 */
}

/* 2. 🍃装饰框核心样式 */
.mesAvatarWrapper::after {
  content: "";
  position: absolute;
  top: 50%;/* 【上下】 */
  left: 43%;/* 【左右】 */
  width: 123%;  /* 【框比头像大15%】 */
  height: 130%; /* 【框比头像高15%】 */

  /* 【修复关键】必须设置display */
  display: block; /* 或 inline-block */

  /* 【修复关键】确保背景图加载 */
  background-image: url('https://i.postimg.cc/pL82wcKk/Image-2630438564745786.png');
  background-size: 100% 100%; /* 完全覆盖 */
  background-repeat: no-repeat;
  background-position: center;

  transform: translate(-50%, -50%);
  z-index: 1; /* 高于头像 */

  /* 调试辅助线 */
  /* border: 1px solid red; */
}

/* 3. 确保头像图片在装饰框下方 */
.mesAvatarWrapper img {
  position: relative;
  z-index: -1; /* 低于装饰框的20 */
}

/* ==============================================
 * 2. 🍃头像容器模块
 * ============================================== */
.mesAvatarWrapper {
  position: absolute;
  top: -178px;           /* 【控制头像在气泡上方的位置】 */
  left: 12%;            /* 【调整头像左右】 */
  transform: translateX(-50%);
  z-index: -1;
}

/* ==============================================
 * 3. 头像图像模块（可自定义形状）
 * ============================================== */
.mesAvatarWrapper .avatar {
  /* 🍃基础尺寸 - 可自定义修改 */
  width: 60px;           /* 头像宽度 */
  height: 65px;          /* 头像高度 */

  /* 形状控制 - 默认圆形 */
  border-radius: 50%;    /* 圆形（50%），可修改为不同值创建椭圆或圆角矩形 */

  /* 外观样式 */
  overflow: hidden;
  border: 0px solid #fff;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0);
  transition: all 0.3s ease;

  /* 旋转效果 */
  transform: rotate(-25deg); /* 顺时针旋转 */
}

.mesAvatarWrapper .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* ==============================================
 * 4. 🍃楼层显示
 * ============================================== */
.mes .mesIDDisplay {

    position: fixed;  
    top: 200;           
    left: 440%;        /* 【楼层左右】 */
    transform: translateX(-50%); 
    z-index: 999;    
    margin-top: 15px; /* 【楼层上下】 */

    /* 简约样式 */
    padding: 2px 12px;
    background: rgba(255, 255, 255, 0.0); /* 【这里可以填楼层显示的背景色，最后一个数字区调整透明度】 */
    border-radius: 4px;
    box-shadow: 90 2px px rgba(0, 0, 0, 0.1);

    /* 保留原有样式 */
    z-index: 2;
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 1);
    font-weight: 900;
    color: #ffffff; /* 【调整楼层显示的颜色】 */
}

/* 其他元素保持原有样式 */
.mes .mes_timer, .mes .tokenCounterDisplay {
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 1.9);
    font-weight: 600;
    text-align: center;
}
/* ==============================================
 * 5. 🍃基础信息位置调整【时间戳等】
 * ============================================== */
/* 消息块容器 */
.mes_block {
  position: relative;
  padding-top: -0px; /* 保持顶部留白 */
  overflow: visible; /* 确保子元素不被裁剪 */
}


/* 父容器设置相对定位 */
.mes_block {
  position: relative;
}

/* 角色名称 */
.mes_block .ch_name {
  position: relative;
  top: -120px; /* 添加单位px */
  left: 100px;
  max-width: calc(100% - 105px);
  min-height: -0px;
  z-index: 10;
}

.mes_block .ch_name {
  color: #8D9498; /* 角色昵称和编辑按钮颜色 */
}


/* 固定时间戳 */
.timestamp {
  color: #2F363A;
  position: absolute; /* 改为绝对定位 */
  top: 103px;         /* 距父容器顶部的距离 */
  left: -9px;          /* 固定在父容器左侧 */
  width: 100%;        /* 确保宽度不挤压 */
  pointer-events: none; /* 防止阻挡下方交互 */
  /* 新增字体样式 */
  font-size: 8px;     /* 设置字体大小（示例值） */
  font-weight: 900;    /* 设置字体粗细（示例值） */
}


/* 编辑按钮 */
.mes_buttons {
  position: relative;
  top: 77px;/* 正值向下 */
  left: -26px;/* 正值向右 */
  z-index: 30; /* 提高层级，确保按钮可点击 */
}


.mes_edit_buttons {
    display: none;
    flex-direction: row;
    column-gap: 5px;
    float: right;
    cursor: pointer;
    padding-bottom: 5px;
    filter: drop-shadow(0px 0px 0px black);
    transition: 0.3s ease-in-out;

    /* 垂直位置控制 */
    position: relative;       /* 确保定位生效 */
    top: 118px;              /* 负数上移 | 正数下移 | 单位可用px/rem/vh等 */

    /* 水平位置控制 */
    right: 29px;            /* 负数右移 | 正数左移 | 单位可用px/rem/vw等 */
}

/* ==============================================
 * 🕒 计时器 & 🔤 字符计数显示组件
 * ============================================== */

.mes {
  position: relative; /* 创建定位上下文 */
}

/* 通用样式 */
.mes .mes_timer,
.mes .tokenCounterDisplay {
  position: fixed; /* 使用固定定位确保不被遮挡 */
  z-index: 2147483647; /* 最高层级 (32位整数最大值) */
  cursor: default;
  opacity: 0.5;
  font-size: calc(var(--mainFontSize) * 0.7);
  font-weight: 900;
  text-align: center;
  padding: 0px 0px;
  border-radius: 0px;
  background: rgba(30, 30, 30, 0.0); /* 半透明白色背景 */
  backdrop-filter: blur(0px); /* 毛玻璃效果 */
  box-shadow: 0 2px 8px rgba(0,0,0,0.0);

  /* 默认位置 - 顶部居中 */
  top: 240px;
  left: 50%;
  transform: translateX(-50%);

  /* 颜色变量 - 便于单独修改 */
  --timer-color: #2F363A;
  --counter-color: #2F363A;
}

/* 单独控制计时器 */
.mes .mes_timer {
  z-index: 2;
  /* 位置调整 */
  top: var(--timer-top, -2px);  /* 【🍃计时器上下】 */
  left: var(--timer-left, 217%);/*【🍃计时器左右】*/
  transform: translateX(var(--timer-translate, -50%));

  /* 颜色控制 */
  color: var(--timer-color, #2F363A);
}

/* 单独控制字符计数 */
.mes .tokenCounterDisplay {
  z-index: 2;
  /* 位置调整 */
  top: var(--counter-top, -2px); /* 【🍃字符上下】 */
  left: var(--counter-left, 114%);/* 【🍃字符左右】 */
  transform: translateX(var(--counter-translate, -0%));

  /* 颜色控制 */
  color: var(--counter-color, #2F363A);
}
/* ==============================================
 * 🧠 外显思维链位置与颜色调整============================================== */
/* 推理头部容器 - 固定定位 */
.mes_reasoning_header {
  position: absolute;         /* 脱离文档流 */
  z-index: 9999;              /* 最顶层显示 */
  top: -85px;                 /* 顶部偏移 */
  left: 52%;                  /* 水平居中定位 */
  transform: translateX(-50%); /* 水平居中修正 */
  cursor: pointer;            /* 手型指针 */
  user-select: none;          /* 禁止文本选择 */
  font-size: calc(var(--mainFontSize) * 0.85); /* 动态字体大小 */
  opacity: 0.9;               /* 轻微透明 */
  transition: all 0.3s ease;  /* 平滑过渡动画 */

  /* 新视觉样式 - 莫兰迪蓝调日间模式 */
  padding: 4px 10px;          /* 内边距 */
  background: #ffffff;        /* 主背景色 */

  border-radius: 3px;         /* 圆角半径 */
  box-shadow: 
    inset 1px 1px 2px rgba(208, 224, 238, 0.8), /* 左上角内陷高光 */
    0 0 0 1px #FFFFFF,        /* 第一层白色描边 */
    0 0 0 2px #D3D3D3,        /* 第二层灰色描边 */
    0 0 0 3px #FFFFFF,        /* 第三层白色描边 */
    2px 2px 4px rgba(193, 208, 215, 0.5); /* 右下角阴影 */
}

/* 悬停效果增强 */
.mes_reasoning_header:hover {
  background: #D0E0EE;        /* 悬停背景色 */
  box-shadow: 
    inset 1px 1px 3px rgba(208, 224, 238, 0.9),
    0 0 0 1px #FFFFFF,
    0 0 0 2px #C1D0D7,
    0 0 0 3px #FFFFFF,
    3px 3px 6px rgba(193, 208, 215, 0.6); /* 增强阴影 */
}

/* 标题文字样式 */
.mes_reasoning_header_title {
  position: relative;
  display: inline-block;
  top: 0px;                   /* 垂直位置 */
  left: -9px;                 /* 向左偏移 */
  color: #2E262F;             /* 深灰色文字 */
  text-shadow: 0 1px 1px rgba(255, 255, 255, 0.7); /* 柔和高光 */
}

/* 推理内容主体 */
.mes_reasoning {
  position: relative;         /* 相对定位 */
  top: -180px;                /* 垂直位置 */
  display: block;
  margin: 135px 0;            /* 上下外边距 */

  /* 新视觉样式 */
  border-left: 3px solid #C1D0D7; /* 左侧装饰条 */
  color: #5A6470;             /* 深蓝灰文字 */
  background: 
    linear-gradient(rgba(234, 242, 249, 0.9), rgba(234, 242, 249, 0.9)), /* 半透明白色叠加 */

  border-radius: 0 8px 8px 0; /* 右侧圆角 */
  box-shadow: 
    inset 2px 2px 4px rgba(208, 224, 238, 0.8), /* 左上角内陷阴影 */
    0 3px 6px rgba(193, 208, 215, 0.4); /* 右下角投影 */
  padding: 15px;              /* 内容内边距 */
  backdrop-filter: blur(2px); /* 背景模糊效果 */
}


/* ===== 基础图标样式 ===== */
.drawer-icon:not(.openIcon) { 
  opacity: 0.5 !important; 
}

/* 通用图标替换样式 */
.drawer-icon {
  background: url('https://i.postimg.cc/BbN6PgTW/Image-2643183090065315.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

.drawer-icon::before {
  display: none !important;
}

/* ===== 特定图标覆盖 ===== */
/* AI响应配置 */
#leftNavDrawerIcon {
  background-image: url('https://i.postimg.cc/BbN6PgTW/Image-2643183090065315.png') !important;
}

/* API连接 */
#API-status-top::before { display: none !important; }
#API-status-top {
  background: url('https://i.postimg.cc/2883RsYC/Image-2643185420880930.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
  font-size: 0 !important;
}

/* AI回复格式化 */
.drawer-icon.fa-font::before { display: none !important; }
.drawer-icon.fa-font {
  background: ur1('https://i.postimg.cc/2883RsYC/Image-2643185420880930.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

/* 世界信息 */
#WIDrawerIcon::before { display: none !important; }
#WIDrawerIcon {
  background: url('https://i.postimg.cc/2883RsYC/Image-2643185420880930.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

/* 用户设置 */
.drawer-icon.fa-user::before { display: none !important; }
.drawer-icon.fa-user {
  background: url('https://i.postimg.cc/BbN6PgTW/Image-2643183090065315.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

/* 背景更换 */
#site_logo .drawer-icon::before,
#site_logo::before { display: none !important; }
#site_logo .drawer-icon {
  background: url('https://i.postimg.cc/2883RsYC/Image-2643185420880930.png') no-repeat center/30px 30px !important;
  width: 30px !important;
  height: 30px !important;
}

/* 扩展功能 */
.drawer-icon.fa-cubes::before { display: none !important; }
