/*——————输入框美化——————*/
#send_form {
  display: flex;
  flex-direction: column;
  width: 93%;
  max-width: 690px;
  margin: 0px auto;
/* 新增底部留白控制 */
  margin-bottom: 20px; /* 调整此值控制留白大小 */
  padding: 8px 20px;
  border-radius: 10px;
  position: relative;
  overflow: hidden;

  /* 青春记事簿主题背景 */
  background-color: #ffffff; /* 深蓝灰背景色，80%透明度 */
  background-image: url('https://i.postimg.cc/v85q59F1/Image-2637354192658429.png'); 
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;

  /* 三层游戏UI描边效果 */
  box-shadow: 
    0 0 0 1px #FFFFFF,          /* 第一层白色描边 - 增强UI层次感 */
    0 0 0 3px #A0B1BC,           /* 第二层蓝灰色描边 - 莫兰迪色调 */
    0 0 0 5px #FFFFFF,           /* 第三层白色描边 - 增强轮廓清晰度 */
    inset 1px 1px 3px rgba(0, 0, 0, 0.3), /* 左上角内陷阴影 - 营造立体感 */
    3px 3px 8px rgba(0, 0, 0, 0.4); /* 右下角阴影 - 增强深度效果 */

  transition: all 0.4s ease;
}

/* 输入框 - 青春记事簿风格 */
#send_form > input[type="text"],
#send_form > .image-url-container > input {
  background: rgba(193, 208, 215, 0.85); /* C1D0D7半透明背景 */
  color: #2C3E50;                   /* 深蓝灰色文字 - 提高可读性 */
  border: 1px solid #A0B1BC;        /* 蓝灰色边框 - 柔和分隔 */
  border-radius: 0px;               
  padding: 12px 15px;
  transition: all 0.3s ease;
  box-shadow: 
    inset 2px 2px 4px rgba(0, 0, 0, 0.1), /* 内陷阴影 - 营造凹陷感 */
    1px 1px 3px rgba(255, 255, 255, 0.5); /* 右下高光 - 增强立体效果 */
}

/* 聚焦状态 - 青春主题激活效果 */
#send_form > input[type="text"]:focus,
#send_form > .image-url-container > input:focus {
  border-color: #D0E0EE;          /* 使用D0E0EE作为焦点色 */
  background: rgba(255, 255, 255, 0.95); /* 聚焦时提高背景透明度 */
  outline: none;
  box-shadow: 
    inset 2px 2px 4px rgba(0, 0, 0, 0.1),
    0 0 6px rgba(208, 224, 238, 0.6); /* 添加焦点光晕效果 */
}

/* 按钮 - 青春记事簿主题 */
#send_form > .button-container > button {
  border: 2px solid #A0B1BC;      /* 蓝灰色边框 */
  background: rgba(193, 208, 215, 0.3); /* C1D0D7半透明背景 */
  color: #2C3E50;                 /* 深蓝灰色文字 */
  border-radius: 0px;             
  padding: 10px 18px;
  font-weight: 500;
  transition: all 0.3s ease;
  letter-spacing: 1px;
  box-shadow: 
    inset 1px 1px 2px rgba(255, 255, 255, 0.4), /* 左上高光 */
    2px 2px 4px rgba(0, 0, 0, 0.2); /* 右下阴影 */
}

/* 按钮悬停 - 青春主题增强 */
#send_form > .button-container > button:hover {
  background: rgba(208, 224, 238, 0.4); /* D0E0EE悬停效果 */
  transform: translateY(-2px);
  box-shadow: 
    inset 1px 1px 2px rgba(255, 255, 255, 0.6),
    3px 3px 8px rgba(0, 0, 0, 0.3); /* 增强阴影效果 */
}

/* 整体悬停 - 青春主题效果 */
#send_form:hover {
  box-shadow: 
    0 0 0 1px #FFFFFF,
    0 0 0 3px #A0B1BC,
    0 0 0 5px #FFFFFF,
    inset 1px 1px 3px rgba(0, 0, 0, 0.3),
    5px 5px 15px rgba(0, 0, 0, 0.5); /* 增强右下阴影 */
  transform: translateY(-3px);
  background-color: rgba(30, 42, 54, 0.9); /* 悬停时加深背景 */
}

/* 日间模式样式 */
@media (prefers-color-scheme: light) {
  #send_form {
    background-color: rgba(208, 224, 238, 0.8); /* D0E0EE日间背景 */
    box-shadow: 
      0 0 0 1px #FFFFFF,
      0 0 0 3px #D3D3D3,           /* 使用D3D3D3作为第二层描边 */
      0 0 0 5px #FFFFFF,
      inset 2px 2px 5px rgba(0, 0, 0, 0.1), /* 增强内陷阴影 */
      4px 4px 10px rgba(0, 0, 0, 0.15); /* 更柔和的右下阴影 */
  }

  #send_form > input[type="text"],
  #send_form > .image-url-container > input {
    background: rgba(255, 255, 255, 0.92); /* 更明亮的背景 */
    color: #1E2A36;                   /* 深色文字 */
    border: 1px solid #C1D0D7;        /* 使用C1D0D7作为边框 */
  }

  #send_form:hover {
    background-color: rgba(208, 224, 238, 0.9); /* 悬停时轻微加深 */
  }
}
