/* 复选框基础样式 - 三层描边 */
input[type='checkbox'] {
  background: #D3D3D3; /* 深蓝灰基底 */
  box-shadow: 
    inset 2px 2px 4px rgba(0, 0, 0, 0.5), /* 左上角内陷阴影 */
    2px 2px 4px rgba(0, 0, 0, 0.4),        /* 右下角阴影 */
    0 0 0 1px #D0E0EE,                     /* 第一层白色描边 */
    0 0 0 2px #8A9BA8,                     /* 第二层灰色描边 */
    0 0 0 3px #D0E0EE;                     /* 第三层白色描边 */
}

/* 悬停状态 - 加深色调 */
input[type='checkbox']:hover {
  background: #32465A;
  box-shadow: 
    inset -2px -2px 4px rgba(0, 0, 0, 0.6),
    3px 3px 5px rgba(0, 0, 0, 0.5),
    0 0 0 1px #E0EBF5,
    0 0 0 2px #7A8B9C,
    0 0 0 3px #E0EBF5;
}

/* 选中状态 - 浅蓝背景 */
input[type='checkbox']:checked {
  background: #D0E0EE; /* 莫兰迪蓝底色 */
  box-shadow: 
    inset -2px -2px 4px rgba(0, 0, 0, 0.3),
    2px 2px 4px rgba(0, 0, 0, 0.3),
    0 0 0 1px #FFFFFF,
    0 0 0 2px #8A9BA8,
    0 0 0 3px #FFFFFF;
}

/* 梅花图标样式 */
input[type='checkbox']:checked::after {
  content: '○';
  font-size: 1.2em;
position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  color: #2A3B4D; /* 深蓝灰图标 */
}

