/*——————标题栏渐变+三层描边系统——————*/
.header-style,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4,
.standoutHeader {
  /* 日间模式基底色 - 柔和的莫兰迪蓝 */
  background: #EAF2F9;

  /* 三层立体描边系统 */
  border: 2px solid #FFFFFF;          /* 第一层：白色描边（提升清新感） */
  outline: 0px solid #D3D3D3;         /* 第二层：灰色描边（增加层次过渡） */
  box-shadow: 
    inset 2px 2px 4px rgba(0, 0, 0, 0.28),  /* 左上内陷阴影（营造凹陷效果） */
    inset -1px -1px 2px rgba(255, 255, 255, 0.0), /* 右下内反光（增强立体感） */
    3px 3px 3px rgba(0, 0, 0, 0.1);  /* 右下外阴影（增加深度） */

  /* 精致圆角 */
  border-radius: 4px;

