/* ===== 文本编辑框美化 ===== */
.reasoning_edit_textarea, .edit_textarea {
    padding: 15px; 
    margin: 0; 
    width: 100%; 
    max-height: 75vh; 
    max-height: 75dvh;
    outline: none; 
    border-radius: 4px; 
    font-size: 13px; 
    line-height: 1.2;
    transition: all 0.4s ease;
    background: #ffffff url('https://i.postimg.cc/PrsGjThD/Image-2630486855588481.png') center/cover;
    border: 1px solid #ffffff; /* 第一层白色描边 */
    box-shadow: 
        0 0 0 1px #d3d3d3,   /* 第二层浅灰描边 */
        0 0 0 2px #ffffff,   /* 第三层白色描边 */
        inset 2px 2px 4px rgba(208, 224, 238, 0.5), /* 左上角浅蓝灰内阴影 */
        inset -1px -1px 2px rgba(255, 255, 255, 0.9), /* 右下角白色内高光 */
        3px 3px 8px rgba(0, 0, 0, 0.08); /* 右下角柔和投影 */
    color: #2d3748; /* 深蓝灰文字 */

    /* 聚焦状态 */
    &:focus {
        box-shadow: 
            0 0 0 1px #c1d0d7,
            0 0 0 2px #ffffff,
            inset 2px 2px 4px rgba(193, 208, 215, 0.6),
            inset -1px -1px 2px rgba(255, 255, 255, 0.9),
            4px 4px 10px rgba(0, 0, 0, 0.1);
    }

    &::placeholder {
        color: #a0aec0; /* 浅蓝灰占位符 */
    }

    /* 滚动条美化 */
    scrollbar-width: thin;
    scrollbar-color: #c1d0d7 #eaf2f9; /* 灰蓝滑块/淡蓝轨道 */

    &::-webkit-scrollbar {
        width: 6px;
        background: #eaf2f9;           
    }

    &::-webkit-scrollbar-thumb {
        background: #c1d0d7;
        border-radius: 3px;
    }
}

