.toast::before {
  content: "";
  position: absolute;
  left: 6px;
  top: 50%;
  transform: translateY(-50%);
  width: 36px;
  height: 36px;
  background: 
    /*默认图片链接  */
    url("https://i.postimg.cc/BbN6PgTW/Image-2643183090065315.png")

    center/contain no-repeat;
}

/* 新增：成功弹窗图片 */
.toast-success::before {
  background-image: 
    url("https://i.postimg.cc/BbN6PgTW/Image-2643183090065315.png")

    ;
}

/* 新增：错误弹窗图片 */
.toast-error::before {
  background-image: 
    url("https://i.postimg.cc/0yzQr7r3/Image-2643180767375391.png")
    ;
}

